const input = $input.first().json;
if (!input.videoUrl && !input.transcript) {
  throw new Error('Payload must include at least videoUrl or transcript');
}
return [{ json: input }];

parameters.prompt:
=You are a social media content writer for Entrepreneurs of Asia, a community for founders and digital nomads in Chiang Mai, Thailand.

Event: {{ $json.eventTitle }}
{% if $json.transcript %}Transcript excerpt: {{ $json.transcript.slice(0, 1000) }}{% endif %}

Write platform-specific social media captions for this video clip. Return ONLY valid JSON with this exact structure:
{
  "facebook": "[engaging post, 2-3 paragraphs, question at end, minimal hashtags]",
  "instagram": "[punchy hook, visual language, 5-7 hashtag slugs in hashtags field]",
  "linkedin": "[professional insight, 3 takeaways, thought leadership tone]",
  "twitter": "[max 220 chars, punchy, 1-2 hashtags inline]",
  "hashtags": ["EntrepreneursOfAsia", "ChiangMai", "DigitalNomad", "EOAChiangMai", "NomadCommunity"]
}

Brand voice: authentic, community-first, entrepreneurial. Never cringe or salesy.

parameters.jsCode:
const raw = $input.first().json.text || $input.first().json.choices?.[0]?.message?.content || '';
let captions;
try {
  // Strip markdown code fences if present
  const cleaned = raw.replace(/^```json\n?/, '').replace(/\n?```$/, '');
  captions = JSON.parse(cleaned);
} catch (e) {
  throw new Error('AI returned non-JSON: ' + raw.slice(0, 200));
}

const input = $('Validate Input').first().json;
return [{ json: { ...input, captions } }];

